It's useful to be able to find topics by tags for external topic management. Maybe I'm inexact, but I haven't found methods in store/store.go for such functionality. Here`s my fast solution, I think it'll illustrate feature.

```
func (TopicsObjMapper) FindTags(tags []string) ([]types.Topic, error) {
	tsubs, err := adp.FindTopics(tags)
	if err != nil {
		return nil, err
	}
	topics := make([]types.Topic, 0, len(tsubs))
	for _, v := range tsubs {
		topic, err := adp.TopicGet(v.Topic)
		if err != nil {
			continue
		}
		topics = append(topics, *topic)
	}
	return topics, nil
}
```

